// src/utils/logging.ts
import * as fs from "fs";
import * as path from "path";
import * as os from "os";
function appendToLog(message, includeTimestamp = true) {
  try {
    const logPath = path.join(os.homedir(), "Desktop", "netlify", "netlify-mcp", "log.txt");
    if (!fs.existsSync(logPath)) {
      return;
    }
    const timestamp = includeTimestamp ? `[${(/* @__PURE__ */ new Date()).toISOString()}] ` : "";
    const logEntry = `${timestamp}${Array.isArray(message) ? message.join(" ") : message}
`;
    fs.appendFileSync(logPath, logEntry);
  } catch (error) {
    console.error(`Error writing to log file: ${error}`);
  }
}
function appendErrorToLog(message, error) {
  let logMessage = `ERROR: ${Array.isArray(message) ? message.join(" ") : message}`;
  if (error) {
    if (error instanceof Error) {
      logMessage += `
Details: ${error.message}`;
      if (error.stack) {
        logMessage += `
Stack: ${error.stack}`;
      }
    } else {
      logMessage += `
Details: ${String(error)}`;
    }
  }
  appendToLog(logMessage);
}

