// src/utils/cmd.ts
import { exec } from "node:child_process";
var runCommand = async (command, options = {}) => {
  return new Promise((resolve2, reject) => {
    const childProcess = exec(
      command,
      {
        cwd: options.cwd || process.cwd(),
        env: { ...process.env, ...options.env },
        timeout: options.timeout || 3e4
        // Default 30 second timeout
      },
      (error, stdout, stderr) => {
        if (error && error.killed) {
          resolve2({
            stdout: stdout || "",
            stderr: `Command timed out after ${options.timeout || 3e4}ms: ${stderr || ""}`,
            exitCode: 124
            // Common exit code for timeout
          });
          return;
        }
        resolve2({
          stdout: stdout || "",
          stderr: stderr || "",
          exitCode: error ? error.code || 1 : 0
        });
      }
    );
  });
};

// netlify/functions/mcp-server/utils.ts
import { EncryptJWT, jwtDecrypt } from "jose";
var JWE_SECRET = process.env.JWE_SECRET || "mysecrtypekey1234567890123456789012345678901234567890";
function getOAuthIssuer() {
  return process.env.OAUTH_ISSUER || "http://localhost:8888";
}
async function createJWE(payload, expiresIn = "1h") {
  const password = JWE_SECRET;
  const secret = new TextEncoder().encode(password.padEnd(32, "0").slice(0, 32));
  const jwe = await new EncryptJWT(payload).setProtectedHeader({ alg: "dir", enc: "A256GCM" }).setExpirationTime(expiresIn).encrypt(secret);
  return jwe;
}
async function decryptJWE(jwe) {
  const password = JWE_SECRET;
  const secret = new TextEncoder().encode(password.padEnd(32, "0").slice(0, 32));
  try {
    const { payload } = await jwtDecrypt(jwe, secret);
    return payload;
  } catch (error) {
    if ("message" in error || "reason" in error) {
      console.error("Failed to decrypt JWE:", error.message || "", error.reason || "", error.code || "", error.claim || "");
    }
    throw new Error("Invalid JWE token. Please reauthenticate or reconnect to the Netlify MCP server.");
  }
}

// src/utils/api-networking.ts
var getAuthTokenMsg = `
You're not logged into Netlify on this computer. Use the netlify cli to login. \`netlify login\`
If you don't have the netlify cli installed, install it by running "npm i -g netlify-cli",
`;
var UNAUTHED_ERROR_PREFIX = "NetlifyUnauthError:";
var NetlifyUnauthError = class extends Error {
  constructor(message) {
    super(`${UNAUTHED_ERROR_PREFIX} ${message || "unauthenticated request to Netlify MCP API"}`);
    this.name = "NetlifyUnauthError";
  }
};
var readTokenFromEnv = async () => {
  try {
    const OSBasedPaths = envPaths("netlify", { suffix: "" });
    const configPath = path2.join(OSBasedPaths.config, "config.json");
    const configData = await fs2.readFile(configPath, { encoding: "utf-8" });
    const parsedData = JSON.parse(configData.toString());
    const userId = parsedData?.userId;
    return parsedData?.users?.[userId]?.auth?.token;
  } catch {
  }
  return "";
};
var getNetlifyAccessToken = async (request) => {
  if (request) {
    const authHeader = request.headers.get("Authorization");
    let token2 = "";
    if (authHeader && authHeader.startsWith("Bearer ")) {
      const bearerToken = authHeader.slice(7);
      if (bearerToken.startsWith("nfu") || bearerToken.startsWith("nfp") || bearerToken.startsWith("nfo")) {
        token2 = bearerToken;
      } else {
        const decrypted = await decryptJWE(bearerToken);
        if (decrypted && typeof decrypted.accessToken === "string") {
          token2 = decrypted.accessToken;
        } else {
          console.error(`decrypted JWE did not contain accessToken. fields it does have:`, Object.keys(decrypted));
        }
      }
    }
    if (!token2) {
      throw new NetlifyUnauthError("no Bearer token found in Authorization header");
    }
    return token2;
  }
  let token = "";
  if (process.env.NETLIFY_PERSONAL_ACCESS_TOKEN) {
    return process.env.NETLIFY_PERSONAL_ACCESS_TOKEN;
  }
  token = await readTokenFromEnv();
  if (!token) {
    const result = await runCommand("netlify login", { env: process.env });
    appendToLog(["Netlify login exit code and output", JSON.stringify(result)]);
    if (result.exitCode === 0) {
      token = await readTokenFromEnv();
    }
    if (!token) {
      throw new NetlifyUnauthError(getAuthTokenMsg);
    }
  }
  return token;
};
var unauthenticatedFetch = async (url, options = {}) => {
  const response = await fetch(url, {
    ...options,
    headers: {
      "user-agent": "netlify-mcp",
      ...options.body ? { "Content-Type": "application/json" } : {},
      ...options.headers || {}
    }
  });
  return response;
};
var authenticatedFetch = async (urlOrPath, options = {}, incomingRequest) => {
  const token = await getNetlifyAccessToken(incomingRequest);
  const url = new URL(urlOrPath, "https://api.netlify.com");
  return unauthenticatedFetch(url.toString(), {
    ...options,
    headers: {
      "Authorization": `Bearer ${token}`,
      ...options.headers || {}
    }
  });
};
var getAPIJSONResult = async (urlOrPath, options = {}, apiInteractionOptions = {}, incomingRequest) => {
  if (!apiInteractionOptions.pagination) {
    const response = await authenticatedFetch(urlOrPath, options, incomingRequest);
    if (response.status === 401 && incomingRequest) {
      throw new NetlifyUnauthError(`Unauthedenticated request to Netlify API. ${urlOrPath}`);
    }
    if (!response.ok) {
      if (apiInteractionOptions.failureCallback) {
        return apiInteractionOptions.failureCallback(response);
      }
      throw new Error(`Failed to fetch API: ${response.status}`);
    }
    const data = await response.text();
    if (!data) {
      return "";
    }
    try {
      return JSON.parse(data);
    } catch (e) {
      if (apiInteractionOptions.failureCallback) {
        return apiInteractionOptions.failureCallback(response);
      }
      return data;
    }
  }
  const currentTime = Date.now();
  const maxDuration = 22e3;
  let apiResults = [];
  let page = 1 + (apiInteractionOptions.pageOffset || 0);
  let pageLimit = apiInteractionOptions.pageLimit || 100;
  const pageSize = apiInteractionOptions.pageSize || 20;
  while (true) {
    const url = new URL(urlOrPath, "https://api.netlify.com");
    url.searchParams.set("page", page.toString());
    url.searchParams.set("page_size", pageSize.toString());
    const response = await authenticatedFetch(url.toString(), options, incomingRequest);
    if (!response.ok) {
      if (apiInteractionOptions.failureCallback) {
        return apiInteractionOptions.failureCallback(response);
      }
      throw new Error(`Failed to fetch API: ${response.status}`);
    }
    const resultRaw = await response.text();
    if (!resultRaw) {
      break;
    }
    const result = JSON.parse(resultRaw);
    const lastResultTime = Date.now();
    const duration = (lastResultTime - currentTime) / 1e3;
    appendToLog(`Fetched page ${page}, received ${result.length} sites, total ${apiResults.length}, duration: ${duration} seconds`);
    if (Array.isArray(result)) {
      apiResults.push(...result);
      appendToLog(`Fetched page ${page}, received ${result.length} sites, total ${apiResults.length}`);
      page++;
      if (result.length < pageSize || page > pageLimit || duration > maxDuration) {
        break;
      }
    } else {
      break;
    }
  }
  return apiResults;
};
var getSiteId = async ({ projectDir }) => {
  const netlifySiteStatePath = path2.join(projectDir, ".netlify", "state.json");
  const data = await fs2.readFile(netlifySiteStatePath);
  const parsedData = JSON.parse(data.toString());
  return parsedData.siteId;
};

// src/context/coding-context.ts
var contextConsumer;
var contextCache = {};
var TEN_MINUTES_MS = 10 * 60 * 1e3;
var getConsumer = () => "netlify-mcp";
var contextConsumerTimestamp = 0;
async function getContextConsumerConfig() {
  const now = Date.now();
  if (contextConsumer && now - contextConsumerTimestamp < TEN_MINUTES_MS) {
    return contextConsumer;
  }
  try {
    const response = await unauthenticatedFetch(`https://docs.netlify.com/ai-context/context-consumers`);
    const data = await response.json();
    if (data?.consumers?.length > 0) {
      contextConsumer = data.consumers.find((c) => c.key === getConsumer());
    }
  } catch (error) {
    appendErrorToLog("Error fetching context consumers:", error);
  }
  if (contextConsumer) {
    contextConsumerTimestamp = Date.now();
  }
  return contextConsumer;
}
async function getNetlifyCodingContext(contextKey) {
  const now = Date.now();
  if (contextCache[contextKey] && now - contextCache[contextKey].timestamp < TEN_MINUTES_MS) {
    return contextCache[contextKey]?.data;
  }
  const consumer = await getContextConsumerConfig();
  if (!consumer || !consumer.contextScopes[contextKey]?.endpoint) {
    console.error("unable to find the context you are looking for. Check docs.netlify.com for more information.");
    return;
  }
  const endpoint = new URL(consumer.contextScopes[contextKey].endpoint);
  endpoint.searchParams.set("consumer", getConsumer());
  let data = "";
  try {
    const response = await unauthenticatedFetch(endpoint.toString());
    data = await response.text();
    if (!data) {
      console.error("unable to find the context you are looking for. Check docs.netlify.com for more information.");
      return;
    }
    const contextFile = {
      key: contextKey,
      config: consumer.contextScopes[contextKey],
      content: data
    };
    contextCache[contextKey] = {
      data: contextFile,
      timestamp: Date.now()
    };
  } catch (error) {
    console.error("Error fetching context:", error);
  }
  return contextCache[contextKey]?.data;
}

// src/utils/version.ts
import { fileURLToPath } from "url";
import { dirname, resolve } from "path";
import { readFileSync } from "fs";
var pkgVersion = "";
var getPackageVersion = () => {
  if (!pkgVersion) {
    try {
      const __filename = fileURLToPath(import.meta.url);
      const __dirname = dirname(__filename);
      const packageJson = JSON.parse(
        readFileSync(resolve(__dirname, "../package.json"), "utf8")
      );
      pkgVersion = packageJson.version;
    } catch (error) {
      pkgVersion = "0.0.0";
    }
  }
  return pkgVersion;
};

// src/utils/compatibility.ts
var checkCompatibility = () => {
  const currentNodeVersion = process?.versions?.node?.split(".")[0];
  if (currentNodeVersion && Number(currentNodeVersion) < 20) {
    throw new Error('This version of Node.js has been "end of lifed" by the Node.js team and is no longer supported. Please upgrade to at least Node.js 20 to use the Netlify MCP.');
  }
};

