// src/tools/extension-tools/change-extension-installation.ts
import { z as z16 } from "zod";

// src/tools/extension-tools/extension-utils.ts
var sdkBaseUrl = "https://api.netlifysdk.com";
var netlifyFunctionsBaseUrl = "https://app.netlify.com/.netlify/functions";
var getSite = async ({ siteId, incomingRequest }) => {
  const res = await authenticatedFetch(`/api/v1/sites/${siteId}`, {}, incomingRequest);
  if (!res.ok) {
    const data = await res.json();
    throw new Error(`Failed to fetch sites, status: ${res.status}, ${data.message}`);
  }
  return await res.json();
};
var getExtensions = async () => {
  const res = await unauthenticatedFetch(`${sdkBaseUrl}/integrations`);
  if (!res.ok) {
    throw new Error(`Failed to fetch extensions`);
  }
  return await res.json();
};
var getExtension = async ({
  accountId,
  extensionSlug,
  request
}) => {
  const res = await authenticatedFetch(
    `${sdkBaseUrl}/${encodeURIComponent(accountId)}/integrations/${encodeURIComponent(extensionSlug)}`,
    {
      headers: {
        "netlify-token": await getNetlifyAccessToken(request),
        "Api-Version": "2"
      }
    },
    request
  );
  if (!res.ok) {
    throw new Error(`Failed to fetch extension with slug '${extensionSlug}'`);
  }
  const extensionData = await res.json();
  return extensionData;
};
var changeExtensionInstallation = async ({
  shouldBeInstalled,
  accountId,
  extensionSlug,
  request
}) => {
  const extensionData = await getExtension({ accountId, extensionSlug, request });
  const res = await authenticatedFetch(`${netlifyFunctionsBaseUrl}/${shouldBeInstalled ? "install" : "uninstall"}-extension`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Cookie: `_nf-auth=${await getNetlifyAccessToken(request)}`
    },
    body: JSON.stringify({
      teamId: accountId,
      slug: extensionSlug,
      hostSiteUrl: extensionData.hostSiteUrl
    })
  }, request);
  if (!res.ok) {
    throw new Error(`Failed to install extension: ${extensionSlug}`);
  }
  const installExtensionData = await res.json();
  return installExtensionData;
};

// src/tools/extension-tools/change-extension-installation.ts
var changeExtensionInstallationParamsSchema = z16.object({
  extensionSlug: z16.string(),
  shouldBeInstalled: z16.boolean(),
  teamId: z16.string().describe("Team id of the current project team. If unsure, ask what Netlify team"),
  siteId: z16.string().optional().describe("Site id of the current project site. If unsure, ask what Netlify site")
});
var changeExtensionInstallationDomainTool = {
  domain: "extension",
  operation: "change-extension-installation",
  inputSchema: changeExtensionInstallationParamsSchema,
  toolAnnotations: {
    readOnlyHint: false
  },
  cb: async ({ extensionSlug, shouldBeInstalled, teamId, siteId }, { request }) => {
    try {
      await changeExtensionInstallation({
        shouldBeInstalled,
        accountId: teamId,
        extensionSlug,
        request
      });
      appendToLog(`Extension "${extensionSlug}" successfully ${shouldBeInstalled ? "installed" : "uninstalled"} on account "${teamId}"`);
      const extensionData = await getExtension({
        accountId: teamId,
        extensionSlug,
        request
      });
      if (extensionData?.uiSurfaces?.includes("extension-team-configuration")) {
        if (shouldBeInstalled) {
          return `Extension has been installed successfully. Configure it here: https://app.netlify.com/team/${teamId}/extension/${extensionSlug}`;
        }
      } else if (siteId && extensionData.uiSurfaces?.includes("extension-top-level-site-configuration")) {
        const site = await getSite({ siteId, incomingRequest: request });
        if (shouldBeInstalled) {
          return `Extension has been installed successfully. Configure it here: https://app.netlify.com/sites/${site.name}/extensions/${extensionSlug}`;
        }
      }
    } catch (error) {
      const errorMessage = error.message || "Failed to install extension";
      appendErrorToLog(errorMessage);
      return `Failed to ${shouldBeInstalled ? "install" : "uninstall"} the extension. Ensure the extension slug is correct but getting the list of extensions. Error: ${errorMessage}`;
    }
    return `Extension ${shouldBeInstalled ? "installed" : "uninstalled"} successfully.`;
  }
};

