var extensionDomainTools = [changeExtensionInstallationDomainTool, getExtensionsDomainTool, getFullExtensionDetailsDomainTool, initializeDatabaseDomainTool];

// src/tools/index.ts
import { z as z20 } from "zod";
var listOfDomainTools = [userDomainTools, deployDomainTools, teamDomainTools, projectDomainTools, extensionDomainTools];
var toSelectorSchema = (domainTool) => {
  return z20.object({
    // domain: z.literal(domainTool.domain),
    operation: z20.literal(domainTool.operation),
    params: domainTool.inputSchema.optional(),
    llmModelName: z20.string().optional(),
    aiAgentName: z20.string().optional()
  });
};
var bindTools = async (server, remoteMCPRequest, verboseMode = false) => {
  const isRemoteMCP = !!remoteMCPRequest;
  listOfDomainTools.forEach((domainTools) => {
    const domain = domainTools[0].domain;
    const filteredDomainTools = domainTools.filter((tool) => {
      if (isRemoteMCP && tool.omitFromRemoteMCP) {
        return false;
      }
      if (!isRemoteMCP && tool.omitFromLocalMCP) {
        return false;
      }
      return true;
    });
    const { readOnlyTools, writeTools } = categorizeToolsByReadWrite(filteredDomainTools);
    if (readOnlyTools.length > 0) {
      registerDomainTools(server, readOnlyTools, domain, "read", remoteMCPRequest, verboseMode);
    }
    if (writeTools.length > 0) {
      registerDomainTools(server, writeTools, domain, "write", remoteMCPRequest, verboseMode);
    }
  });
};
var registerDomainTools = (server, tools, domain, operationType, remoteMCPRequest, verboseMode = false) => {
  const toolOperations = tools.map((tool) => tool.operation);
  const readOnlyIndicator = operationType === "read" ? " (read-only)" : "";
  if (verboseMode) {
    tools.forEach((tool) => {
      const toolName = `netlify-${domain}-${tool.operation}`;
      const toolDescription = `${tool.operation} operation for Netlify ${domain}${readOnlyIndicator}`;
      const schemaShape = tool.inputSchema.shape || {};
      server.registerTool(toolName, {
        description: toolDescription,
        inputSchema: schemaShape,
        annotations: {
          readOnlyHint: operationType === "read"
        }
      }, async (...args) => {
        checkCompatibility();
        try {
          await getNetlifyAccessToken(remoteMCPRequest);
        } catch (error) {
          if (error instanceof NetlifyUnauthError && remoteMCPRequest) {
            throw new NetlifyUnauthError();
          }
          return {
            content: [{ type: "text", text: error?.message || "Failed to get Netlify token" }],
            isError: true
          };
        }
        appendToLog(`${toolName} operation: ${JSON.stringify(args)}`);
        const result = await tool.cb(args[0], { request: remoteMCPRequest, isRemoteMCP: !!remoteMCPRequest });
        appendToLog(`${domain} operation result: ${JSON.stringify(result)}`);
        return {
          content: [{ type: "text", text: JSON.stringify(result) }]
        };
      });
    });
  } else {
    const paramsSchema = {
      // @ts-ignore
      selectSchema: tools.length > 1 ? z20.union(tools.map((tool) => toSelectorSchema(tool))) : toSelectorSchema(tools[0])
    };
    const friendlyOperationType = operationType === "read" ? "reader" : "updater";
    const toolName = `netlify-${domain}-services-${friendlyOperationType}`;
    const toolDescription = `Select and run one of the following Netlify ${operationType} operations${readOnlyIndicator} ${toolOperations.join(", ")}`;
    server.registerTool(toolName, {
      description: toolDescription,
      inputSchema: paramsSchema,
      annotations: {
        readOnlyHint: operationType === "read"
      }
    }, async (...args) => {
      checkCompatibility();
      try {
        await getNetlifyAccessToken(remoteMCPRequest);
      } catch (error) {
        if (error instanceof NetlifyUnauthError && remoteMCPRequest) {
          throw new NetlifyUnauthError();
        }
        return {
          content: [{ type: "text", text: error?.message || "Failed to get Netlify token" }],
          isError: true
        };
      }
      appendToLog(`${toolName} operation: ${JSON.stringify(args)}`);
      const selectedSchema = args[0]?.selectSchema;
      if (!selectedSchema) {
        return {
          content: [{ type: "text", text: "Failed to select a valid operation. Retry the MCP operation but select the operation and provide the right inputs." }]
        };
      }
      const operation = selectedSchema.operation;
      const subtool = tools.find((subtool2) => subtool2.operation === operation);
      if (!subtool) {
        return {
          content: [{ type: "text", text: "Agent called the wrong MCP tool for this operation." }]
        };
      }
      const result = await subtool.cb(selectedSchema.params || {}, { request: remoteMCPRequest, isRemoteMCP: !!remoteMCPRequest });
      appendToLog(`${domain} operation result: ${JSON.stringify(result)}`);
      return {
        content: [{ type: "text", text: JSON.stringify(result) }]
      };
    });
  }
};

// netlify-mcp.ts
var proxyPath = process.argv[process.argv.indexOf("--proxy-path") + 1] || void 0;
if (process.argv.includes("--proxy-path") && proxyPath) {
  (async () => {
    console.log("Starting deployment process...");
    checkCompatibility();
    const deployDirectory = process.cwd();
    const siteId = process.argv[process.argv.indexOf("--site-id") + 1] || void 0;
    const proxyUrl = new URL(proxyPath).toString();
    const uploadPath = `${proxyUrl}/api/v1/sites/${siteId}/builds`;
    const uploadingInterval = setInterval(() => {
      console.log("Uploading your project...");
    }, 3e3);
    const { deployId, buildId } = await zipAndBuild({ deployDirectory, siteId, uploadPath });
    clearInterval(uploadingInterval);
    console.log("Deploy process has started...", JSON.stringify({ deployId, buildId, watchDeployProgress: `https://app.netlify.com/sites/${siteId}/deploys/${deployId}` }));
    if (process.argv.includes("--no-wait")) {
      process.exit(0);
    }
    const deployEndpoint = `${proxyUrl}/api/v1/deploys/${deployId}`;
    let lastState = "";
    setInterval(async () => {
      const deployLookup = await fetch(deployEndpoint);
      if (deployLookup.ok) {
        const deploy = await deployLookup.json();
        if (deploy.state === "ready") {
          console.log("Deploy is ready!", JSON.stringify({ deployId, buildId, siteUrl: deploy.url }));
          process.exit(0);
        } else if (deploy.state === "error") {
          console.error("Deploy failed!", JSON.stringify({ deployId, buildId, deployInfo: `https://app.netlify.com/sites/${siteId}/deploys/${deployId}` }));
          process.exit(1);
        }
        const sameAsLastState = lastState === deploy.state;
        console.log(`This project deploy is ${sameAsLastState ? "still" : "now"} ${deploy.state}. Waiting for it to finish...`);
        lastState = deploy.state;
      } else {
        console.error("Error fetching deploy status:", deployLookup.statusText);
        process.exit(0);
      }
    }, 5e3);
  })();
} else {
  const verboseMode = process.argv.includes("--verbose");
  const server = new McpServer({
    name: "netlify-mcp",
    version: getPackageVersion()
  });
  const contextConsumer2 = await getContextConsumerConfig();
  const availableContextTypes = Object.keys(contextConsumer2?.contextScopes || {});
  const creationTypeEnum = z21.enum(availableContextTypes);
  server.registerTool(
    "netlify-coding-rules",
    {
      description: "ALWAYS call when writing serverless or Netlify code. required step before creating or editing any type of functions, Netlify sdk/library  usage, etc.",
      inputSchema: {
        creationType: creationTypeEnum
      },
      annotations: {
        readOnlyHint: true
      }
    },
    async ({ creationType }) => {
      checkCompatibility();
      const context = await getNetlifyCodingContext(creationType);
      const text = context?.content || "";
      return {
        content: [{ type: "text", text }]
      };
    }
  );
  await bindTools(server, void 0, verboseMode);
  const transport = new StdioServerTransport();
  await server.connect(transport);
}
